#!/usr/bin/env node
/**
 * 抖音视频发布脚本 - 使用 Playwright MCP
 * 
 * 用法: node douyin-publish.js <视频路径> <标题> [描述] [标签]
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

// 抖音创作者平台 URL
const DOUYIN_CREATOR_URL = 'https://creator.douyin.com/';

// Cookie 保存路径
const COOKIE_PATH = path.join(__dirname, 'douyin-cookies.json');

async function loadCookies(page) {
    try {
        if (fs.existsSync(COOKIE_PATH)) {
            const cookies = JSON.parse(fs.readFileSync(COOKIE_PATH, 'utf8'));
            await page.context().addCookies(cookies);
            console.log('✅ Cookie 已加载');
            return true;
        }
    } catch (e) {
        console.log('⚠️ 加载 Cookie 失败:', e.message);
    }
    return false;
}

async function saveCookies(page) {
    try {
        const cookies = await page.context().cookies();
        fs.writeFileSync(COOKIE_PATH, JSON.stringify(cookies, null, 2));
        console.log('✅ Cookie 已保存');
    } catch (e) {
        console.log('⚠️ 保存 Cookie 失败:', e.message);
    }
}

async function checkLoginStatus(page) {
    try {
        // 检查是否有登录相关的元素
        const loginButton = await page.$('text=登录');
        const avatar = await page.$('.avatar-image, [class*="avatar"]');

        if (loginButton) {
            console.log('❌ 未登录');
            return false;
        }

        if (avatar) {
            console.log('✅ 已登录');
            return true;
        }

        // 尝试访问创作者中心
        await page.goto(DOUYIN_CREATOR_URL);
        await page.waitForTimeout(3000);

        // 再次检查
        const stillLoginButton = await page.$('text=登录');
        return !stillLoginButton;

    } catch (e) {
        console.log('⚠️ 检查登录状态失败:', e.message);
        return false;
    }
}

async function publishVideo(page, videoPath, title, description = '', tags = '') {
    console.log('\n🚀 开始发布视频...');

    try {
        // 1. 访问创作者平台
        console.log('📍 访问抖音创作者平台...');
        await page.goto(DOUYIN_CREATOR_URL);
        await page.waitForTimeout(5000);

        // 2. 检查/等待登录
        console.log('🔐 检查登录状态...');
        const isLoggedIn = await checkLoginStatus(page);

        if (!isLoggedIn) {
            console.log('⚠️ 请先手动登录抖音账号');
            console.log('   1. 等待页面加载');
            console.log('   2. 点击登录按钮');
            console.log('   3. 扫码或短信验证');
            console.log('   4. 登录成功后按回车继续...');

            // 等待用户手动登录
            await page.waitForTimeout(60000); // 给用户60秒时间登录

            // 保存登录后的 cookie
            await saveCookies(page);
        }

        // 3. 找到上传按钮并点击
        console.log('📤 寻找上传按钮...');

        // 尝试多种可能的上传按钮选择器
        const uploadSelectors = [
            'text=上传视频',
            'text=发布视频',
            'text=投稿',
            'text=创作',
            '[class*="upload"]',
            '[class*="publish"]',
            'button:has-text("上传")',
            'button:has-text("发布")'
        ];

        let uploadButton = null;
        for (const selector of uploadSelectors) {
            try {
                uploadButton = await page.$(selector);
                if (uploadButton) {
                    console.log(`✅ 找到上传按钮: ${selector}`);
                    break;
                }
            } catch (e) {
                // 继续尝试下一个选择器
            }
        }

        if (!uploadButton) {
            console.log('⚠️ 未找到上传按钮，可能需要手动操作');
            console.log('   页面可能已更新，请手动点击上传按钮');
        } else {
            await uploadButton.click();
            await page.waitForTimeout(3000);
        }

        // 4. 上传视频文件
        console.log(`📁 上传视频: ${videoPath}`);

        // 等待文件输入框出现
        const fileInput = await page.waitForSelector('input[type="file"]', { timeout: 10000 });

        if (!fileInput) {
            throw new Error('未找到文件上传输入框');
        }

        await fileInput.setInputFiles(videoPath);
        console.log('✅ 视频文件已选择');

        // 等待上传完成
        console.log('⏳ 等待上传完成...');
        await page.waitForTimeout(10000); // 等待10秒

        // 5. 填写标题
        console.log(`📝 填写标题: ${title}`);

        const titleSelectors = [
            'input[placeholder*="标题"]',
            'input[placeholder*="请输入"]',
            'textarea[placeholder*="标题"]',
            '[class*="title"] input',
            '[class*="title"] textarea'
        ];

        let titleInput = null;
        for (const selector of titleSelectors) {
            try {
                titleInput = await page.$(selector);
                if (titleInput) {
                    await titleInput.fill(title);
                    console.log('✅ 标题已填写');
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        if (!titleInput) {
            console.log('⚠️ 未找到标题输入框，可能需要手动填写');
        }

        // 6. 填写描述
        if (description) {
            console.log(`📝 填写描述: ${description}`);
            // 类似的方式查找描述输入框
            // ...
        }

        // 7. 添加标签
        if (tags) {
            console.log(`🏷️ 添加标签: ${tags}`);
            // 类似的方式添加标签
            // ...
        }

        // 8. 发布
        console.log('🚀 点击发布按钮...');

        const publishSelectors = [
            'text=发布',
            'text=确认发布',
            'text=立即发布',
            'button:has-text("发布")'
        ];

        let publishButton = null;
        for (const selector of publishSelectors) {
            try {
                publishButton = await page.$(selector);
                if (publishButton) {
                    await publishButton.click();
                    console.log('✅ 已点击发布按钮');
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        if (!publishButton) {
            console.log('⚠️ 未找到发布按钮，可能需要手动点击');
        }

        // 等待发布完成
        console.log('⏳ 等待发布完成...');
        await page.waitForTimeout(10000);

        // 保存 Cookie
        await saveCookies(page);

        console.log('\n✅ 视频发布流程完成！');

    } catch (error) {
        console.error('\n❌ 发布失败:', error.message);
        console.error(error.stack);
        throw error;
    }
}

// 主函数
async function main() {
    const args = process.argv.slice(2);

    if (args.length < 2) {
        console.log('用法: node douyin-publish.js <视频路径> <标题> [描述] [标签]');
        console.log('');
        console.log('示例:');
        console.log('  node douyin-publish.js /path/to/video.mp4 "我的视频标题"');
        console.log('  node douyin-publish.js /path/to/video.mp4 "标题" "描述" "标签1,标签2"');
        process.exit(1);
    }

    const [videoPath, title, description = '', tags = ''] = args;

    // 检查视频文件是否存在
    if (!fs.existsSync(videoPath)) {
        console.error(`❌ 视频文件不存在: ${videoPath}`);
        process.exit(1);
    }

    console.log('🎬 抖音视频发布工具');
    console.log('====================');
    console.log(`📁 视频: ${videoPath}`);
    console.log(`📝 标题: ${title}`);
    console.log(`📝 描述: ${description || '(无)'}`);
    console.log(`🏷️ 标签: ${tags || '(无)'}`);
    console.log('====================\n');

    // 启动浏览器
    console.log('🚀 启动浏览器...');

    let browser;
    try {
        // 使用 headless 模式（不需要 X 服务器）
        browser = await chromium.launch({
            headless: true,
            slowMo: 50
        });
        console.log('✅ 浏览器启动成功 (headless 模式)');
    } catch (e) {
        console.error('❌ 浏览器启动失败:', e.message);
        throw e;
    }

    const page = await browser.newPage();

    // 设置视口
    await page.setViewportSize({ width: 1280, height: 800 });

    try {
        // 加载 Cookie
        await loadCookies(page);

        // 发布视频
        await publishVideo(page, videoPath, title, description, tags);

        console.log('\n✅ 完成！浏览器将保持打开 60 秒...');
        await page.waitForTimeout(60000);

    } catch (error) {
        console.error('\n❌ 错误:', error.message);
        console.log('\n⚠️ 浏览器将保持打开，方便调试...');
        await page.waitForTimeout(300000); // 保持 5 分钟
    } finally {
        await browser.close();
    }
}

// 运行主函数
main().catch(console.error);

