    } catch (e) {
        console.log('⚠️ 加载 Cookie 失败:', e.message);
    }
    return false;
}

async function saveCookies(page) {
    try {
        const cookies = await page.context().cookies();
        fs.writeFileSync(COOKIE_PATH, JSON.stringify(cookies, null, 2));
        console.log('✅ Cookie 已保存');
    } catch (e) {
        console.log('⚠️ 保存 Cookie 失败:', e.message);
    }
}

async function checkLoginStatus(page) {
    try {
        // 检查是否有登录相关的元素
        const loginButton = await page.$('text=登录');
        const avatar = await page.$('.avatar-image, [class*="avatar"], [class*="Avatar"]');

        if (loginButton) {
            console.log('❌ 未登录');
            return false;
        }

        if (avatar) {
            console.log('✅ 已登录');
            return true;
        }

        // 尝试访问创作者中心
        await page.goto(XHS_CREATOR_URL);
        await page.waitForTimeout(3000);

        // 再次检查
        const stillLoginButton = await page.$('text=登录');
        return !stillLoginButton;

    } catch (e) {
        console.log('⚠️ 检查登录状态失败:', e.message);
        return false;
    }
}

async function performLogin(page, phoneNumber) {
    console.log('\n🔐 开始登录流程...');

    try {
        // 1. 访问登录页面
        console.log('📍 访问登录页面...');
        await page.goto(XHS_LOGIN_URL);
        await page.waitForTimeout(3000);

        // 2. 等待页面加载，查找登录表单
        console.log('⏳ 等待页面加载...');

        // 截图查看当前页面状态
        await page.screenshot({ path: 'xhs-login-page.png', fullPage: true });
        console.log('📸 已保存页面截图: xhs-login-page.png');

        // 3. 尝试找到手机号输入框
        const phoneSelectors = [
            'input[type="tel"]',
            'input[placeholder*="手机"]',
            'input[placeholder*="手机号"]',
            'input[name*="phone"]',
            'input[name*="mobile"]',
            '[class*="phone"] input',
            '[class*="login"] input[type="text"]'
        ];

        let phoneInput = null;
        for (const selector of phoneSelectors) {
            try {
                phoneInput = await page.$(selector);
                if (phoneInput) {
                    console.log(`✅ 找到手机号输入框: ${selector}`);
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        if (!phoneInput) {
            console.log('⚠️ 未找到手机号输入框，可能需要手动操作');
            console.log('   请手动输入手机号并点击获取验证码');

            // 等待用户手动操作
            const rl = createRL();
            await askQuestion(rl, '\n按回车键继续（手动登录完成后）...');
            rl.close();

            // 保存 cookie
            await saveCookies(page);
            return true;
        }

        // 4. 输入手机号
        console.log(`📱 输入手机号: ${phoneNumber}`);
        await phoneInput.click();
        await phoneInput.fill(phoneNumber);
        await page.waitForTimeout(1000);

        // 5. 查找并点击获取验证码按钮
        console.log('🔍 查找获取验证码按钮...');

        const codeButtonSelectors = [
            'text=获取验证码',
            'text=发送验证码',
            'button:has-text("验证码")',
            'button:has-text("获取")',
            '[class*="code"] button',
            '[class*="verify"] button'
        ];

        let codeButton = null;
        for (const selector of codeButtonSelectors) {
            try {
                codeButton = await page.$(selector);
                if (codeButton) {
                    console.log(`✅ 找到验证码按钮: ${selector}`);
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        if (codeButton) {
            console.log('📤 点击获取验证码...');
            await codeButton.click();
            console.log('✅ 验证码已发送，请查看短信');
        } else {
            console.log('⚠️ 未找到验证码按钮，请手动点击');
        }

        // 6. 等待用户输入验证码
        const rl = createRL();
        const verificationCode = await askQuestion(rl, '\n请输入收到的验证码: ');
        rl.close();

        if (!verificationCode || verificationCode.trim().length === 0) {
            console.log('❌ 未输入验证码，登录取消');
            return false;
        }

        // 7. 输入验证码
        console.log('📝 输入验证码...');

        const codeInputSelectors = [
            'input[placeholder*="验证码"]',
            'input[type="number"]',
            'input[name*="code"]',
            'input[name*="verify"]',
            '[class*="code"] input'
        ];

        let codeInput = null;
        for (const selector of codeInputSelectors) {
            try {
                codeInput = await page.$(selector);
                if (codeInput) {
                    await codeInput.fill(verificationCode.trim());
                    console.log('✅ 验证码已输入');
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        if (!codeInput) {
            console.log('⚠️ 未找到验证码输入框，请手动输入');
        }

        // 8. 查找并点击登录按钮
        console.log('🔍 查找登录按钮...');

        const loginButtonSelectors = [
            'text=登录',
            'text=确认',
            'text=提交',
            'button[type="submit"]',
            'button:has-text("登录")',
            'button:has-text("确认")'
        ];

        let loginButton = null;
        for (const selector of loginButtonSelectors) {
            try {
                loginButton = await page.$(selector);
                if (loginButton) {
                    console.log(`✅ 找到登录按钮: ${selector}`);
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        if (loginButton) {
            console.log('🚀 点击登录按钮...');
            await loginButton.click();
            console.log('⏳ 等待登录完成...');
            await page.waitForTimeout(5000);
        } else {
            console.log('⚠️ 未找到登录按钮，请手动点击');
        }

        // 9. 检查登录状态
        const loginSuccess = await checkLoginStatus(page);

        if (loginSuccess) {
            console.log('✅ 登录成功！');
            await saveCookies(page);
            return true;
        } else {
            console.log('❌ 登录可能失败，请检查页面状态');
            // 保存截图供调试
            await page.screenshot({ path: 'xhs-login-failed.png', fullPage: true });
            console.log('📸 已保存调试截图: xhs-login-failed.png');
            return false;
        }

    } catch (error) {
        console.error('\n❌ 登录过程出错:', error.message);
        console.error(error.stack);

        // 保存截图供调试
        try {
            await page.screenshot({ path: 'xhs-login-error.png', fullPage: true });
            console.log('📸 已保存调试截图: xhs-login-error.png');
        } catch (e) {
            // 忽略截图错误
        }

        return false;
    }
}

// 主函数
async function main() {
    const args = process.argv.slice(2);

    // 手机号可以通过参数传入，或使用默认的
    const phoneNumber = args[0] || '18962397865';

    console.log('🍠 小红书创作者平台登录工具');
    console.log('========================');
    console.log(`📱 手机号: ${phoneNumber}`);
    console.log('========================\n');

    // 启动浏览器
    console.log('🚀 启动浏览器...');

    let browser;
    try {
        // 使用 headless 模式
        browser = await chromium.launch({
            headless: true,
            slowMo: 50
        });
        console.log('✅ 浏览器启动成功 (headless 模式)');
    } catch (e) {
        console.error('❌ 浏览器启动失败:', e.message);
        throw e;
    }

    const page = await browser.newPage();

    // 设置视口
    await page.setViewportSize({ width: 1280, height: 800 });

    try {
        // 加载 Cookie
        await loadCookies(page);

        // 检查登录状态
        const isLoggedIn = await checkLoginStatus(page);

        if (isLoggedIn) {
            console.log('✅ 已经是登录状态！');
        } else {
            // 执行登录
            const success = await performLogin(page, phoneNumber);
            if (!success) {
                console.log('\n❌ 登录失败');
            }
        }

        // 保持浏览器打开一段时间
        console.log('\n⏳ 浏览器将保持打开 60 秒...');
        await page.waitForTimeout(60000);

    } catch (error) {
        console.error('\n❌ 错误:', error.message);
        console.log('\n⚠️ 浏览器将保持打开，方便调试...');
        await page.waitForTimeout(300000); // 保持 5 分钟
    } finally {
        await browser.close();
    }
}

// 运行主函数
main().catch(console.error);

