#!/usr/bin/env node
/**
 * 小红书创作者平台扫码登录脚本 - 使用 Playwright
 * 
 * 用法: node xiaohongshu-login-qr.js
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');
const readline = require('readline');

// 小红书创作者平台 URL
const XHS_CREATOR_URL = 'https://creator.xiaohongshu.com/';
const XHS_LOGIN_URL = 'https://creator.xiaohongshu.com/login';

// Cookie 保存路径
const COOKIE_PATH = path.join(__dirname, 'xiaohongshu-cookies.json');

// 创建 readline 接口
function createRL() {
    return readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });
}

// 提问函数
function askQuestion(rl, question) {
    return new Promise((resolve) => {
        rl.question(question, (answer) => {
            resolve(answer);
        });
    });
}

async function loadCookies(page) {
    try {
        if (fs.existsSync(COOKIE_PATH)) {
            const cookies = JSON.parse(fs.readFileSync(COOKIE_PATH, 'utf8'));
            await page.context().addCookies(cookies);
            console.log('✅ Cookie 已加载');
            return true;
        }
    } catch (e) {
        console.log('⚠️ 加载 Cookie 失败:', e.message);
    }
    return false;
}

async function saveCookies(page) {
    try {
        const cookies = await page.context().cookies();
        fs.writeFileSync(COOKIE_PATH, JSON.stringify(cookies, null, 2));
        console.log('✅ Cookie 已保存');
    } catch (e) {
        console.log('⚠️ 保存 Cookie 失败:', e.message);
    }
}

async function checkLoginStatus(page) {
    try {
        // 等待页面加载
        await page.waitForTimeout(3000);

        // 检查是否有登录相关的元素
        const loginButton = await page.$('text=登录');
        const avatar = await page.$('.avatar-image, [class*="avatar"], [class*="Avatar"], img[alt*="头像"]');
        const userName = await page.$('[class*="username"], [class*="nickname"]');

        if (avatar || userName) {
            console.log('✅ 已登录 (检测到头像或用户名)');
            return true;
        }

        if (loginButton) {
            console.log('❌ 未登录 (检测到登录按钮)');
            return false;
        }

        // 尝试访问创作者中心
        await page.goto(XHS_CREATOR_URL);
        await page.waitForTimeout(3000);

        // 再次检查
        const stillLoginButton = await page.$('text=登录');
        const hasAvatar = await page.$('.avatar-image, [class*="avatar"]');

        if (hasAvatar) return true;
        return !stillLoginButton;

    } catch (e) {
        console.log('⚠️ 检查登录状态失败:', e.message);
        return false;
    }
}

async function performQRCodeLogin(page) {
    console.log('\n📱 开始扫码登录流程...\n');

    try {
        // 1. 访问登录页面
        console.log('📍 正在打开小红书登录页面...');
        await page.goto(XHS_LOGIN_URL);
        await page.waitForTimeout(3000);

        // 2. 等待二维码加载
        console.log('⏳ 等待页面加载...');
        await page.waitForTimeout(2000);

        // 3. 截图保存二维码页面
        await page.screenshot({ path: 'xhs-qr-login.png', fullPage: false });
        console.log('📸 已保存页面截图: xhs-qr-login.png');

        // 4. 查找二维码图片
        console.log('🔍 查找二维码...');

        const qrSelectors = [
            'img[src*="qr"]',
            'img[alt*="二维码"]',
            'img[alt*="QR"]',
            '[class*="qr"] img',
            '[class*="qrcode"] img',
            'canvas[class*="qr"]',
            'canvas[class*="qrcode"]'
        ];

        let qrElement = null;
        let qrSelector = null;

        for (const selector of qrSelectors) {
            try {
                qrElement = await page.$(selector);
                if (qrElement) {
                    qrSelector = selector;
                    console.log(`✅ 找到二维码: ${selector}`);
                    break;
                }
            } catch (e) {
                // 继续尝试
            }
        }

        // 5. 保存二维码图片（如果找到）
        if (qrElement) {
            try {
                // 如果是 img 标签，直接截图元素
                if (qrSelector.includes('img')) {
                    await qrElement.screenshot({ path: 'xhs-qr-code.png' });
                    console.log('📸 已保存二维码图片: xhs-qr-code.png');
                } else if (qrSelector.includes('canvas')) {
                    // 如果是 canvas，尝试导出为图片
                    await page.evaluate((selector) => {
                        const canvas = document.querySelector(selector);
                        if (canvas) {
                            const link = document.createElement('a');
                            link.download = 'qrcode.png';
                            link.href = canvas.toDataURL();
                            link.click();
                        }
                    }, qrSelector);
                    console.log('📸 已尝试导出 canvas 二维码');
                }
            } catch (e) {
                console.log('⚠️ 保存二维码图片失败:', e.message);
            }
        } else {
            console.log('⚠️ 未找到二维码元素，但已保存页面截图');
        }

        // 6. 提示用户扫码
        console.log('\n' + '='.repeat(50));
        console.log('📱 请使用小红书APP扫码登录');
        console.log('='.repeat(50));
        console.log('步骤：');
        console.log('  1. 打开小红书APP');
        console.log('  2. 点击"我的" → 右上角扫一扫');
        console.log('  3. 扫描页面上的二维码');
        console.log('  4. 在手机上确认登录');
        console.log('='.repeat(50) + '\n');

        // 7. 等待用户扫码完成
        const rl = createRL();
        await askQuestion(rl, '扫码完成后，按回车键继续...');
        rl.close();

        // 8. 等待一段时间让登录完成
        console.log('⏳ 等待登录完成...');
        await page.waitForTimeout(5000);

        // 9. 检查登录状态
        const loginSuccess = await checkLoginStatus(page);

        if (loginSuccess) {
            console.log('✅ 扫码登录成功！');
            await saveCookies(page);
            return true;
        } else {
            console.log('⚠️ 登录状态不确定，请检查页面');
            // 保存截图供调试
            await page.screenshot({ path: 'xhs-login-status.png', fullPage: true });
            console.log('📸 已保存状态截图: xhs-login-status.png');
            return false;
        }

    } catch (error) {
        console.error('\n❌ 扫码登录过程出错:', error.message);
        console.error(error.stack);

        // 保存截图供调试
        try {
            await page.screenshot({ path: 'xhs-qr-error.png', fullPage: true });
            console.log('📸 已保存错误截图: xhs-qr-error.png');
        } catch (e) {
            // 忽略截图错误
        }

        return false;
    }
}

// 主函数
async function main() {
    console.log('🍠 小红书创作者平台扫码登录工具');
    console.log('================================');
    console.log('支持: 扫码登录');
    console.log('================================\n');

    // 启动浏览器
    console.log('🚀 启动浏览器...');

    let browser;
    try {
        // 使用 headless 模式
        browser = await chromium.launch({
            headless: true,
            slowMo: 50
        });
        console.log('✅ 浏览器启动成功 (headless 模式)');
    } catch (e) {
        console.error('❌ 浏览器启动失败:', e.message);
        throw e;
    }

    const page = await browser.newPage();

    // 设置视口
    await page.setViewportSize({ width: 1280, height: 800 });

    try {
        // 加载 Cookie
        await loadCookies(page);

        // 检查登录状态
        const isLoggedIn = await checkLoginStatus(page);

        if (isLoggedIn) {
            console.log('✅ 已经是登录状态！');
        } else {
            // 执行扫码登录
            const success = await performQRCodeLogin(page);
            if (!success) {
                console.log('\n⚠️ 扫码登录可能未成功，请检查');
            }
        }

        // 保持浏览器打开一段时间
        console.log('\n⏳ 浏览器将保持打开 60 秒...');
        await page.waitForTimeout(60000);

    } catch (error) {
        console.error('\n❌ 错误:', error.message);
        console.log('\n⚠️ 浏览器将保持打开，方便调试...');
        await page.waitForTimeout(300000); // 保持 5 分钟
    } finally {
        await browser.close();
    }
}

// 运行主函数
main().catch(console.error);

