#!/usr/bin/env node
/**
 * 小红书扫码登录 - 优化版
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const XHS_LOGIN_URL = 'https://creator.xiaohongshu.com/login';
const COOKIE_PATH = path.join(__dirname, 'xiaohongshu-cookies.json');

async function saveCookies(page) {
    try {
        const cookies = await page.context().cookies();
        fs.writeFileSync(COOKIE_PATH, JSON.stringify(cookies, null, 2));
        console.log('✅ Cookie 已保存');
    } catch (e) {
        console.log('⚠️ 保存 Cookie 失败:', e.message);
    }
}

async function findAndClickQRLogin(page) {
    console.log('🔍 查找扫码登录选项...');

    // 等待页面完全加载
    await page.waitForTimeout(3000);

    // 可能的扫码登录按钮选择器
    const qrButtonSelectors = [
        'text=扫码登录',
        'text=二维码登录',
        'text=扫码',
        '[class*="qr"]',
        '[class*="qrcode"]',
        '[class*="scan"]',
        'button:has-text("扫码")',
        'div:has-text("扫码"):has(img)'
    ];

    for (const selector of qrButtonSelectors) {
        try {
            const element = await page.$(selector);
            if (element) {
                console.log(`✅ 找到扫码登录按钮: ${selector}`);
                await element.click();
                console.log('🖱️ 已点击扫码登录');
                await page.waitForTimeout(2000);
                return true;
            }
        } catch (e) {
            // 继续尝试
        }
    }

    console.log('⚠️ 未找到扫码登录按钮，可能页面已经是扫码模式');
    return false;
}

async function captureQRCode(page) {
    console.log('📸 正在截取二维码...');

    // 等待二维码加载
    await page.waitForTimeout(3000);

    // 保存完整页面截图
    await page.screenshot({ path: 'xhs-qr-full.png', fullPage: false });
    console.log('✅ 已保存页面截图: xhs-qr-full.png');

    // 尝试找到二维码元素并单独截图
    const qrSelectors = [
        'img[alt*="二维码"]',
        'img[alt*="qr"]',
        'img[src*="qr"]',
        '[class*="qr"] img',
        '[class*="qrcode"] img',
        'canvas[class*="qr"]',
        'canvas[class*="qrcode"]'
    ];

    for (const selector of qrSelectors) {
        try {
            const element = await page.$(selector);
            if (element) {
                await element.screenshot({ path: 'xhs-qr-code-only.png' });
                console.log('✅ 已保存二维码图片: xhs-qr-code-only.png');
                return true;
            }
        } catch (e) {
            // 继续尝试
        }
    }

    console.log('⚠️ 未能单独截取二维码，请查看完整截图 xhs-qr-full.png');
    return false;
}

async function main() {
    console.log('🍠 小红书扫码登录工具 v2');
    console.log('========================\n');

    let browser;
    try {
        browser = await chromium.launch({
            headless: false,
            slowMo: 100
        });
        console.log('✅ 浏览器已启动 (可见模式)\n');

        const page = await browser.newPage();
        await page.setViewportSize({ width: 1280, height: 900 });

        // 访问登录页面
        console.log('📍 打开小红书登录页面...');
        await page.goto(XHS_LOGIN_URL);

        // 查找并点击扫码登录
        await findAndClickQRLogin(page);

        // 截取二维码
        await captureQRCode(page);

        console.log('\n' + '='.repeat(50));
        console.log('📱 请使用小红书APP扫码');
        console.log('='.repeat(50));
        console.log('二维码已保存到：');
        console.log('  - xhs-qr-full.png (完整页面)');
        console.log('  - xhs-qr-code-only.png (仅二维码)');
        console.log('\n扫码完成后，浏览器会保持打开...');
        console.log('='.repeat(50));

        // 保持浏览器打开
        await new Promise(() => {});

    } catch (error) {
        console.error('\n❌ 错误:', error.message);
        if (browser) await browser.close();
    }
}

main();

