#!/usr/bin/env node
/**
 * 小红书登录脚本 v3 - 支持手机验证码 + 扫码登录
 * 
 * 用法: node xiaohongshu-login-v3.js [模式]
 * 模式: phone (默认) | qr | both
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');
const readline = require('readline');

const XHS_LOGIN_URL = 'https://creator.xiaohongshu.com/login';
const COOKIE_PATH = path.join(__dirname, 'xiaohongshu-cookies.json');

// 默认手机号
const DEFAULT_PHONE = '18962397865';

// 创建 readline 接口
function createRL() {
    return readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });
}

function askQuestion(rl, question) {
    return new Promise((resolve) => {
        rl.question(question, (answer) => {
            resolve(answer);
        });
    });
}

async function saveCookies(page) {
    try {
        const cookies = await page.context().cookies();
        fs.writeFileSync(COOKIE_PATH, JSON.stringify(cookies, null, 2));
        console.log('✅ Cookie 已保存');
    } catch (e) {
        console.log('⚠️ 保存 Cookie 失败:', e.message);
    }
}

// ============ 模式1: 手机号验证码登录 ============
async function phoneLogin(page, phoneNumber) {
    console.log('\n📱 开始手机号验证码登录...\n');

    try {
        // 访问登录页面
        await page.goto(XHS_LOGIN_URL);
        await page.waitForTimeout(3000);

        // 确保在手机号登录模式（点击手机号登录tab）
        const phoneTabSelectors = [
            'text=手机号登录',
            'text=手机登录',
            '[class*="tab"]:has-text("手机")',
            'button:has-text("手机")'
        ];

        for (const selector of phoneTabSelectors) {
            try {
                const tab = await page.$(selector);
                if (tab) {
                    await tab.click();
                    console.log('✅ 切换到手机号登录');
                    await page.waitForTimeout(1000);
                    break;
                }
            } catch (e) {}
        }

        // 输入手机号
        const phoneSelectors = [
            'input[type="tel"]',
            'input[placeholder*="手机"]',
            'input[placeholder*="手机号"]',
            'input[name*="phone"]',
            'input[name*="mobile"]'
        ];

        let phoneInput = null;
        for (const selector of phoneSelectors) {
            try {
                phoneInput = await page.$(selector);
                if (phoneInput) {
                    await phoneInput.fill(phoneNumber);
                    console.log(`✅ 已输入手机号: ${phoneNumber}`);
                    break;
                }
            } catch (e) {}
        }

        if (!phoneInput) {
            console.log('⚠️ 未找到手机号输入框，请手动输入');
        }

        // 点击获取验证码
        const codeButtonSelectors = [
            'text=获取验证码',
            'text=发送验证码',
            'button:has-text("验证码")',
            'button:has-text("获取")'
        ];

        for (const selector of codeButtonSelectors) {
            try {
                const btn = await page.$(selector);
                if (btn) {
                    await btn.click();
                    console.log('✅ 已点击"获取验证码"');
                    break;
                }
            } catch (e) {}
        }

        // 等待用户输入验证码
        console.log('\n' + '='.repeat(50));
        console.log('📱 验证码已发送到你的手机');
        console.log('='.repeat(50));

        const rl = createRL();
        const code = await askQuestion(rl, '\n请输入收到的验证码: ');
        rl.close();

        if (!code || code.trim().length === 0) {
            console.log('❌ 未输入验证码');
            return false;
        }

        // 输入验证码
        const codeSelectors = [
            'input[placeholder*="验证码"]',
            'input[type="number"]',
            'input[name*="code"]'
        ];

        for (const selector of codeSelectors) {
            try {
                const input = await page.$(selector);
                if (input) {
                    await input.fill(code.trim());
                    console.log('✅ 已输入验证码');
                    break;
                }
            } catch (e) {}
        }

        // 点击登录
        const loginSelectors = [
            'text=登录',
            'text=确认',
            'button[type="submit"]'
        ];

        for (const selector of loginSelectors) {
            try {
                const btn = await page.$(selector);
                if (btn) {
                    await btn.click();
                    console.log('🚀 已点击登录');
                    break;
                }
            } catch (e) {}
        }

        await page.waitForTimeout(5000);

        // 保存 cookie
        await saveCookies(page);

        console.log('\n✅ 登录流程完成！');
        return true;

    } catch (error) {
        console.error('❌ 登录失败:', error.message);
        return false;
    }
}

// ============ 模式2: 扫码登录 ============
async function qrLogin(page) {
    console.log('\n📱 开始扫码登录...\n');

    try {
        // 访问登录页面
        await page.goto(XHS_LOGIN_URL);
        await page.waitForTimeout(3000);

        // 查找并点击扫码登录（通常在右上角）
        const qrTabSelectors = [
            'text=扫码登录',
            'text=二维码登录',
            'text=扫码',
            '[class*="qr"]',
            '[class*="scan"]',
            'button:has-text("扫码")',
            '[class*="tab"]:has-text("扫码")',
            // 右上角图标类
            '[class*="icon"][class*="qr"]',
            '[class*="icon"][class*="scan"]'
        ];

        let foundQR = false;
        for (const selector of qrTabSelectors) {
            try {
                const element = await page.$(selector);
                if (element) {
                    await element.click();
                    console.log(`✅ 已切换到扫码登录: ${selector}`);
                    foundQR = true;
                    await page.waitForTimeout(3000);
                    break;
                }
            } catch (e) {}
        }

        if (!foundQR) {
            console.log('⚠️ 未找到扫码登录按钮，当前页面可能已经是扫码模式');
        }

        // 截图保存二维码
        await page.screenshot({ path: 'xhs-qr-code.png', fullPage: false });
        console.log('\n📸 已保存二维码截图: xhs-qr-code.png');

        // 尝试找到二维码元素单独截图
        const qrSelectors = [
            'img[alt*="二维码"]',
            'img[alt*="qr"]',
            '[class*="qr"] img',
            '[class*="qrcode"] img',
            'canvas[class*="qr"]'
        ];

        for (const selector of qrSelectors) {
            try {
                const element = await page.$(selector);
                if (element) {
                    await element.screenshot({ path: 'xhs-qr-only.png' });
                    console.log('📸 已单独保存二维码: xhs-qr-only.png');
                    break;
                }
            } catch (e) {}
        }

        console.log('\n' + '='.repeat(50));
        console.log('📱 请使用小红书APP扫码登录');
        console.log('='.repeat(50));
        console.log('步骤：');
        console.log('  1. 打开小红书APP');
        console.log('  2. 点击"我的" → 右上角扫一扫');
        console.log('  3. 扫描二维码');
        console.log('  4. 在手机上确认登录');
        console.log('='.repeat(50));

        // 保持浏览器打开，等待扫码
        console.log('\n⏳ 等待扫码完成（浏览器保持打开）...');
        console.log('扫码成功后按 Ctrl+C 结束脚本\n');

        await new Promise(() => {});

    } catch (error) {
        console.error('❌ 扫码登录失败:', error.message);
        throw error;
    }
}

// ============ 主程序 ============
async function main() {
    const mode = process.argv[2] || 'phone';

    console.log('🍠 小红书创作者平台登录工具 v3');
    console.log('================================');
    console.log(`模式: ${mode === 'qr' ? '扫码登录' : mode === 'phone' ? '手机验证码' : '两者都支持'}`);
    console.log('================================\n');

    const browser = await chromium.launch({
        headless: false,
        slowMo: 100
    });

    const page = await browser.newPage();
    await page.setViewportSize({ width: 1280, height: 900 });

    try {
        if (mode === 'phone') {
            await phoneLogin(page, DEFAULT_PHONE);
        } else if (mode === 'qr') {
            await qrLogin(page);
        } else if (mode === 'both') {
            // 先尝试扫码，如果用户不想扫码再转手机
            console.log('🔄 先尝试扫码登录...\n');
            await qrLogin(page);
        }
    } catch (error) {
        console.error('❌ 发生错误:', error.message);
    }
}

main().catch(console.error);

