#!/usr/bin/env node
/**
 * 小红书二维码获取 - Headless模式
 */

const { chromium } = require('playwright');

async function main() {
    console.log('🚀 启动浏览器 (headless 模式)...');

    const browser = await chromium.launch({
        headless: true  // 无头模式，不需要 X 服务器
    });

    const page = await browser.newPage();
    await page.setViewportSize({ width: 1280, height: 900 });

    console.log('📍 打开小红书登录页...');
    await page.goto('https://creator.xiaohongshu.com/login');
    await page.waitForTimeout(3000);

    // 截图 - 查看当前页面状态
    await page.screenshot({ path: 'xhs-step1.png' });
    console.log('📸 已保存 step1: xhs-step1.png');

    // 查找并点击"扫码登录"切换按钮（通常在右上角或标签页）
    const qrTabSelectors = [
        'text=扫码登录',
        'text=二维码登录', 
        'text=扫码',
        '[class*="qr"]',
        '[class*="scan"]',
        'button:has-text("扫码")'
    ];

    let clicked = false;
    for (const selector of qrTabSelectors) {
        try {
            const element = await page.$(selector);
            if (element) {
                await element.click();
                console.log(`✅ 点击了: ${selector}`);
                clicked = true;
                await page.waitForTimeout(3000);
                break;
            }
        } catch (e) {}
    }

    if (!clicked) {
        console.log('⚠️ 未找到扫码登录按钮，可能页面默认显示二维码');
    }

    // 保存二维码截图
    await page.screenshot({ path: 'xhs-qr-code.png' });
    console.log('📸 已保存二维码: xhs-qr-code.png');

    console.log('\n✅ 完成！');
    console.log('文件位置:');
    console.log('  - xhs-step1.png (初始页面)');
    console.log('  - xhs-qr-code.png (二维码)');

    await browser.close();
}

main().catch(console.error);

